#include "stencil.h"

void stencil(TYPE orig[row_size * col_size],
             TYPE sol[row_size * col_size],
             TYPE filter[f_size]) {
    int r, c, k1, k2;
    TYPE temp, mul;

    stencil_label1: for (r = 0; r < row_size - 2; r++) {
        #pragma HLS LOOP_TRIPCOUNT min=126 max=126
        stencil_label2: for (c = 0; c < col_size - 2; c++) {
            #pragma HLS LOOP_TRIPCOUNT min=62 max=62
            #pragma HLS PIPELINE II=9
            temp = (TYPE)0;
            stencil_label3: for (k1 = 0; k1 < 3; k1++) {
                stencil_label4: for (k2 = 0; k2 < 3; k2++) {
                    #pragma HLS UNROLL
                    mul = filter[k1 * 3 + k2] * orig[(r + k1) * col_size + c + k2];
                    temp += mul;
                }
            }
            sol[(r * col_size) + c] = temp;
        }
    }
}


void workload(TYPE* orig, TYPE* sol, TYPE* filter) {
    #pragma HLS INTERFACE m_axi port=orig offset=slave bundle=gmem max_read_burst_length=256 max_write_burst_length=256
    #pragma HLS INTERFACE m_axi port=sol offset=slave bundle=gmem max_read_burst_length=256 max_write_burst_length=256
    #pragma HLS INTERFACE m_axi port=filter offset=slave bundle=gmem max_read_burst_length=256 max_write_burst_length=256
    #pragma HLS INTERFACE s_axilite port=orig bundle=control
    #pragma HLS INTERFACE s_axilite port=sol bundle=control
    #pragma HLS INTERFACE s_axilite port=filter bundle=control
    #pragma HLS INTERFACE s_axilite port=return bundle=control

    TYPE l_orig[row_size * col_size];
    TYPE l_sol[row_size * col_size];
    TYPE l_filter[f_size];
    int i;

    copy_orig: for (i = 0; i < row_size * col_size; i++) {
        #pragma HLS PIPELINE II=4
        l_orig[i] = orig[i];
    }

    copy_filter: for (i = 0; i < f_size; i++) {
        #pragma HLS PIPELINE II=1
        l_filter[i] = filter[i];
    }

    stencil(l_orig, l_sol, l_filter);

    copy_sol: for (i = 0; i < row_size * col_size; i++) {
        #pragma HLS PIPELINE II=4
        sol[i] = l_sol[i];
    }
}

#include "spmv.h"

void spmv(TYPE val[NNZ], int32_t cols[NNZ], int32_t rowDelimiters[N + 1],
          TYPE vec[N], TYPE out[N]) {
    int i, j;
    TYPE sum, Si;

    spmv_1: for (i = 0; i < N; i++) {
        #pragma HLS PIPELINE II=1
        sum = 0; Si = 0;
        int tmp_begin = rowDelimiters[i];
        int tmp_end = rowDelimiters[i + 1];
        spmv_2: for (j = tmp_begin; j < tmp_end; j++) {
            Si = val[j] * vec[cols[j]];
            sum = sum + Si;
        }
        out[i] = sum;
    }
}


extern "C" {
void workload(TYPE* val, int32_t* cols, int32_t* rowDelimiters,
              TYPE* vec, TYPE* out) {
    #pragma HLS INTERFACE m_axi port=val offset=slave bundle=gmem
    #pragma HLS INTERFACE m_axi port=cols offset=slave bundle=gmem
    #pragma HLS INTERFACE m_axi port=rowDelimiters offset=slave bundle=gmem
    #pragma HLS INTERFACE m_axi port=vec offset=slave bundle=gmem
    #pragma HLS INTERFACE m_axi port=out offset=slave bundle=gmem
    #pragma HLS INTERFACE s_axilite port=val bundle=control
    #pragma HLS INTERFACE s_axilite port=cols bundle=control
    #pragma HLS INTERFACE s_axilite port=rowDelimiters bundle=control
    #pragma HLS INTERFACE s_axilite port=vec bundle=control
    #pragma HLS INTERFACE s_axilite port=out bundle=control
    #pragma HLS INTERFACE s_axilite port=return bundle=control

    TYPE l_val[NNZ];
    int32_t l_cols[NNZ];
    int32_t l_rowDelimiters[N + 1];
    TYPE l_vec[N];
    TYPE l_out[N];
    int i;

    #pragma HLS ARRAY_PARTITION variable=l_vec cyclic factor=4 dim=1

    for (i = 0; i < NNZ; i++) { 
        l_val[i] = val[i]; 
        l_cols[i] = cols[i]; 
    }
    for (i = 0; i < N + 1; i++) {
        l_rowDelimiters[i] = rowDelimiters[i];
    }
    for (i = 0; i < N; i++) {
        l_vec[i] = vec[i];
    }

    spmv(l_val, l_cols, l_rowDelimiters, l_vec, l_out);

    for (i = 0; i < N; i++) {
        out[i] = l_out[i];
    }
}
